"use strict";
(function (global) {
  function runCustomersInit() {
    if (
      global.BioTernCustomersRuntime &&
      typeof global.BioTernCustomersRuntime.initDefaults === "function"
    ) {
      global.BioTernCustomersRuntime.initDefaults();
    }
  }

  if (
    global.BioTernRuntimeBoot &&
    typeof global.BioTernRuntimeBoot.boot === "function"
  ) {
    global.BioTernRuntimeBoot.boot({
      name: "customers-init runtime",
      run: runCustomersInit,
    });
    return;
  }

  function bootFallback() {
    try {
      runCustomersInit();
    } catch (err) {
      if (global.console && typeof global.console.warn === "function") {
        global.console.warn("customers-init runtime failed", err);
      }
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", bootFallback);
  } else {
    bootFallback();
  }
})(window);
